import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';
import { Link } from 'react-router-dom';

const Home = () => {
  const { user } = useAuth();
  const [tours, setTours] = useState([]);

  useEffect(() => {
    const fetchTours = async () => {
      try {
        const res = await axiosInstance.get('/api/tours');
        setTours(res.data);
      } catch (err) { console.error(err); }
    };
    fetchTours();
  }, []);

  return (
    <div className="max-w-[420px] mx-auto bg-white min-h-screen flex flex-col font-sans">
      {/* Header Area */}
      <div className="p-6 flex justify-between items-center bg-white">
        <div>
          <p className="text-gray-400 text-xs font-medium">Good morning!</p>
          <h2 className="font-bold text-lg text-gray-800">Admin ({user?.username || 'Guest'})</h2>
        </div>
        <div className="flex items-center space-x-3">
          <div className="w-10 h-10 rounded-full border-2 border-gray-100 overflow-hidden shadow-sm">
            <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${user?.username}`} alt="avatar" />
          </div>
          <button className="relative p-2">
            <span className="text-xl">🔔</span>
            <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border border-white"></span>
          </button>
        </div>
      </div>

      {/* Order List Card - 還原截圖中的卡片設計 */}
      <div className="px-6 mb-8">
        <div className="bg-white border border-gray-50 p-6 rounded-[28px] shadow-[0_10px_40px_-15px_rgba(0,0,0,0.05)] flex items-center">
          <div className="w-14 h-14 bg-yellow-50 rounded-2xl flex items-center justify-center text-2xl mr-4 shadow-inner">
            📋
          </div>
          <div>
            <p className="text-gray-400 text-xs font-bold uppercase tracking-widest">Order List</p>
            <p className="text-3xl font-black text-gray-900 mt-1">0</p>
          </div>
        </div>
      </div>

      {/* View Package List */}
      <div className="px-6 flex-1 overflow-y-auto">
        <h3 className="font-bold text-gray-800 mb-5 text-base px-1">View Package</h3>
        <div className="space-y-6">
          {tours.map(tour => (
            <div key={tour._id} className="flex space-x-4 items-center group">
              <div className="w-24 h-24 rounded-[24px] overflow-hidden shadow-md">
                <img src={tour.imageUrl || "https://via.placeholder.com/150"} className="w-full h-full object-cover" alt="" />
              </div>
              <div className="flex-1">
                <h4 className="font-bold text-gray-800 text-[15px] leading-tight">{tour.title}</h4>
                <p className="text-gray-400 text-[11px] font-bold mt-1 uppercase tracking-tighter">{tour.location}</p>
                <div className="mt-3">
                  <span className={`px-4 py-1 rounded-lg text-[11px] font-black ${tour.status === 'Available' ? 'bg-[#ADFF2F] text-green-900' : 'bg-red-500 text-white'}`}>
                    {tour.status === 'Available' ? `AUD ${tour.price}` : 'SOLD OUT'}
                  </span>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Bottom Button - 修正名稱為設計稿要求 */}
      <div className="p-6 sticky bottom-0 bg-white/80 backdrop-blur-md">
        <Link to="/manage-tours" className="block w-full bg-[#00A651] text-white text-center font-bold py-4 rounded-2xl shadow-xl shadow-green-100 active:scale-95 transition-all">
          Add Tour Package
        </Link>
      </div>
    </div>
  );
};

export default Home;
